namespace sv_834a335d5690413c8ab4bfc6dc86453d.Services;

/// <summary>
/// Scoped service (per-circuit in Blazor Server) that holds the currently
/// selected warehouse and notifies all subscribers when the selection changes.
/// </summary>
public sealed class WarehouseStateService
{
    public static IReadOnlyList<Warehouse> AvailableWarehouses { get; } =
    [
        new("wh-1", "Warehouse A — East"),
        new("wh-2", "Warehouse B — West"),
        new("wh-3", "Warehouse C — Central"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public Warehouse CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    /// <summary>
    /// Raised on the calling thread whenever the selected warehouse changes.
    /// Subscribers must call InvokeAsync / StateHasChanged themselves.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public sealed record Warehouse(string Id, string Name);

namespace sv_834a335d5690413c8ab4bfc6dc86453d.Services;

/// <summary>
/// Scoped service (per-circuit) that polls for low-stock alerts and
/// broadcasts results to all subscribed components via an event.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Raised whenever a new poll result arrives.
    /// All subscribed components should re-render.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query — returns a random int 0-15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component that needs polling becomes visible.
    /// Ref-counted: polling runs while at least one subscriber is active.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Call when a component that needs polling is removed / hidden.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            CancelPolling();
        }
    }

    /// <summary>
    /// Triggers an immediate poll (e.g. after a warehouse change) and
    /// notifies all subscribers.
    /// </summary>
    public async Task RefreshNowAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire an initial poll immediately so subscribers don't wait 10 s.
        await RefreshNowAsync();

        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
                OnAlertCountChanged?.Invoke();
            }
        }
        catch (OperationCanceledException) { /* expected on stop */ }
    }

    private void CancelPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose() => CancelPolling();
}

