/// <summary>
/// Scoped service (per-circuit in Blazor Server) that holds the currently
/// selected warehouse and notifies all subscribers when the selection changes.
/// </summary>
public sealed class WarehouseStateService
{
    public static IReadOnlyList<Warehouse> AvailableWarehouses { get; } =
    [
        new("wh-1", "Warehouse A — East"),
        new("wh-2", "Warehouse B — West"),
        new("wh-3", "Warehouse C — Central"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public Warehouse CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    /// <summary>
    /// Raised on the calling thread whenever the selected warehouse changes.
    /// Subscribers must call InvokeAsync / StateHasChanged themselves.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public sealed record Warehouse(string Id, string Name);

