@using sv_834a335d5690413c8ab4bfc6dc86453d.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<select class="form-select form-select-sm" value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged"
        style="max-width: 220px;">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? "");
        // Trigger an immediate re-poll for the new warehouse.
        await AlertService.RefreshNowAsync();
    }

    private void HandleWarehouseChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
    }
}

@using sv_834a335d5690413c8ab4bfc6dc86453d.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<span class="badge rounded-pill @BadgeClass">@AlertService.LatestLowStockCount</span>

@code {
    private string BadgeClass =>
        AlertService.LatestLowStockCount > 0 ? "bg-danger" : "bg-success";

    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += HandleAlertChanged;
    }

    private void HandleAlertChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= HandleAlertChanged;
    }
}

